import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

export default function Navbar() {
  const navigate = useNavigate();
  const [showContact, setShowContact] = useState(false);
  const [form, setForm] = useState({
    firstName: "",
    lastName: "",
    mobile: "",
    email: "",
    message: "",
    captcha: "",
  });
  const [captchaCode] = useState("p q t 5 s");
  const [submitted, setSubmitted] = useState(false);

  const storedUser = localStorage.getItem("user");
  const user = storedUser ? JSON.parse(storedUser) : null;

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/");
  };

  const handleSubmit = () => {
    if (!form.firstName || !form.mobile || !form.email || !form.captcha) {
      alert("Please fill all required fields!");
      return;
    }
    setSubmitted(true);
    setTimeout(() => {
      setShowContact(false);
      setSubmitted(false);
      setForm({
        firstName: "",
        lastName: "",
        mobile: "",
        email: "",
        message: "",
        captcha: "",
      });
    }, 2000);
  };

  return (
    <>
      <nav className="bg-gray-800 text-white p-4 flex justify-between items-center">
        <div className="font-bold">Doctor App</div>
        <div className="flex items-center gap-4">
          <button onClick={() => navigate("/")} className="hover:text-blue-400">
            Home
          </button>
          <button
            onClick={() => setShowContact(true)}
            className="hover:text-blue-400"
          >
            Contact Us
          </button>
          {user ? (
            <button
              className="bg-red-500 px-3 py-1 rounded hover:bg-red-800"
              onClick={handleLogout}
            >
              Logout
            </button>
          ) : (
            <span>Welcome On This App</span>
          )}
        </div>
      </nav>

      {showContact && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center"
          style={{ background: "rgba(0,0,0,0.6)" }}
          onClick={() => setShowContact(false)}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: "linear-gradient(135deg, #4a5568, #2d3748)",
              borderRadius: "16px",
              padding: "32px",
              width: "480px",
              boxShadow: "0 20px 60px rgba(0,0,0,0.4)",
            }}
          >
            {/* Title */}
            <h2
              style={{
                color: "#fff",
                fontSize: "22px",
                fontWeight: "700",
                textAlign: "center",
                marginBottom: "24px",
                borderBottom: "2px solid rgba(255,255,255,0.2)",
                paddingBottom: "12px",
              }}
            >
              Contact Us
            </h2>

            {submitted ? (
              <div
                style={{
                  textAlign: "center",
                  color: "#68d391",
                  fontSize: "18px",
                  padding: "40px 0",
                }}
              >
                ✅ Message Sent Successfully!
              </div>
            ) : (
              <>
                {/* Row 1 - First Name & Last Name */}
                <div
                  style={{ display: "flex", gap: "12px", marginBottom: "12px" }}
                >
                  <div style={{ flex: 1, position: "relative" }}>
                    <span
                      style={{
                        position: "absolute",
                        left: "10px",
                        top: "50%",
                        transform: "translateY(-50%)",
                        color: "#a0aec0",
                      }}
                    >
                      👤
                    </span>
                    <input
                      placeholder="First Name *"
                      value={form.firstName}
                      onChange={(e) =>
                        setForm({ ...form, firstName: e.target.value })
                      }
                      style={{
                        width: "100%",
                        padding: "10px 10px 10px 34px",
                        borderRadius: "8px",
                        border: "1px solid #718096",
                        background: "rgba(255,255,255,0.1)",
                        color: "#fff",
                        fontSize: "13px",
                        outline: "none",
                        boxSizing: "border-box",
                      }}
                    />
                  </div>
                  <div style={{ flex: 1, position: "relative" }}>
                    <span
                      style={{
                        position: "absolute",
                        left: "10px",
                        top: "50%",
                        transform: "translateY(-50%)",
                        color: "#a0aec0",
                      }}
                    >
                      👤
                    </span>
                    <input
                      placeholder="Last Name"
                      value={form.lastName}
                      onChange={(e) =>
                        setForm({ ...form, lastName: e.target.value })
                      }
                      style={{
                        width: "100%",
                        padding: "10px 10px 10px 34px",
                        borderRadius: "8px",
                        border: "1px solid #718096",
                        background: "rgba(255,255,255,0.1)",
                        color: "#fff",
                        fontSize: "13px",
                        outline: "none",
                        boxSizing: "border-box",
                      }}
                    />
                  </div>
                </div>

                {/* Row 2 - Mobile & Email */}
                <div
                  style={{ display: "flex", gap: "12px", marginBottom: "12px" }}
                >
                  <div style={{ flex: 1, position: "relative" }}>
                    <span
                      style={{
                        position: "absolute",
                        left: "10px",
                        top: "50%",
                        transform: "translateY(-50%)",
                        color: "#a0aec0",
                      }}
                    >
                      📱
                    </span>
                    <input
                      placeholder="Mobile No *"
                      value={form.mobile}
                      onChange={(e) =>
                        setForm({ ...form, mobile: e.target.value })
                      }
                      style={{
                        width: "100%",
                        padding: "10px 10px 10px 34px",
                        borderRadius: "8px",
                        border: "1px solid #718096",
                        background: "rgba(255,255,255,0.1)",
                        color: "#fff",
                        fontSize: "13px",
                        outline: "none",
                        boxSizing: "border-box",
                      }}
                    />
                  </div>
                  <div style={{ flex: 1, position: "relative" }}>
                    <span
                      style={{
                        position: "absolute",
                        left: "10px",
                        top: "50%",
                        transform: "translateY(-50%)",
                        color: "#a0aec0",
                      }}
                    >
                      ✉️
                    </span>
                    <input
                      placeholder="Email ID *"
                      value={form.email}
                      onChange={(e) =>
                        setForm({ ...form, email: e.target.value })
                      }
                      style={{
                        width: "100%",
                        padding: "10px 10px 10px 34px",
                        borderRadius: "8px",
                        border: "1px solid #718096",
                        background: "rgba(255,255,255,0.1)",
                        color: "#fff",
                        fontSize: "13px",
                        outline: "none",
                        boxSizing: "border-box",
                      }}
                    />
                  </div>
                </div>

                {/* Message */}
                <div style={{ marginBottom: "12px" }}>
                  <textarea
                    placeholder="Message"
                    value={form.message}
                    onChange={(e) =>
                      setForm({ ...form, message: e.target.value })
                    }
                    rows={3}
                    style={{
                      width: "100%",
                      padding: "10px",
                      borderRadius: "8px",
                      border: "1px solid #718096",
                      background: "rgba(255,255,255,0.1)",
                      color: "#fff",
                      fontSize: "13px",
                      outline: "none",
                      resize: "none",
                      boxSizing: "border-box",
                    }}
                  />
                </div>

                {/* Captcha */}
                <div style={{ marginBottom: "16px" }}>
                  <input
                    placeholder="Please type the characters *"
                    value={form.captcha}
                    onChange={(e) =>
                      setForm({ ...form, captcha: e.target.value })
                    }
                    style={{
                      width: "100%",
                      padding: "10px",
                      borderRadius: "8px",
                      border: "1px solid #718096",
                      background: "rgba(255,255,255,0.1)",
                      color: "#fff",
                      fontSize: "13px",
                      outline: "none",
                      boxSizing: "border-box",
                      marginBottom: "8px",
                    }}
                  />
                  <div
                    style={{
                      background: "rgba(255,255,255,0.15)",
                      borderRadius: "6px",
                      padding: "8px 12px",
                      display: "inline-block",
                      letterSpacing: "6px",
                      fontSize: "18px",
                      fontWeight: "700",
                      color: "#e2e8f0",
                      fontFamily: "monospace",
                      marginBottom: "4px",
                    }}
                  >
                    {captchaCode}
                  </div>
                  <div style={{ color: "#a0aec0", fontSize: "11px" }}>
                    This helps us prevent spam, thank you.
                  </div>
                </div>

                {/* Submit Button */}
                <button
                  onClick={handleSubmit}
                  style={{
                    width: "100%",
                    padding: "12px",
                    background: "linear-gradient(135deg, #2b6cb0, #2c5282)",
                    border: "none",
                    borderRadius: "8px",
                    color: "#fff",
                    fontSize: "15px",
                    fontWeight: "600",
                    cursor: "pointer",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    gap: "8px",
                  }}
                >
                  Submit ➤
                </button>
              </>
            )}
          </div>
        </div>
      )}
    </>
  );
}
